import{_ as a,o,c as l,ae as i}from"./chunks/framework.S2bkbjdq.js";const h=JSON.parse('{"title":"Monad, Cleaker, and Public Roots","description":"","frontmatter":{},"headers":[],"relativePath":"Monad-vs-Cleaker.md","filePath":"Monad-vs-Cleaker.md"}'),c={name:"Monad-vs-Cleaker.md"};function n(t,e,r,d,s,p){return o(),l("div",null,[...e[0]||(e[0]=[i('<h1 id="monad-cleaker-and-public-roots" tabindex="-1">Monad, Cleaker, and Public Roots <a class="header-anchor" href="#monad-cleaker-and-public-roots" aria-label="Permalink to &quot;Monad, Cleaker, and Public Roots&quot;">​</a></h1><p>This page fixes a common confusion in the stack:</p><ul><li><code>.me</code> is the semantic kernel</li><li><code>monad.ai</code> is the daemon that runs it</li><li><code>cleaker</code> is the ledger interface and public semantic network layer</li><li><code>cleaker.me</code> is the canonical public root that adopts that layer</li></ul><p>These are related, but they are not the same thing.</p><h2 id="core-roles" tabindex="-1">Core Roles <a class="header-anchor" href="#core-roles" aria-label="Permalink to &quot;Core Roles&quot;">​</a></h2><h3 id="me" tabindex="-1"><code>.me</code> <a class="header-anchor" href="#me" aria-label="Permalink to &quot;`.me`&quot;">​</a></h3><p><code>.me</code> owns:</p><ul><li>identity</li><li>keys</li><li>spaces</li><li>secrets</li><li>snapshots</li><li>semantic execution</li></ul><p>It is the local sovereign kernel.</p><p>Examples:</p><ul><li><code>me://self:read/profile</code></li><li><code>me://self:write/profile.name</code></li><li><code>me://self:explain/profile.netWorth</code></li></ul><h3 id="monad-ai" tabindex="-1"><code>monad.ai</code> <a class="header-anchor" href="#monad-ai" aria-label="Permalink to &quot;`monad.ai`&quot;">​</a></h3><p><code>monad.ai</code> is the daemon host.</p><p>It owns:</p><ul><li>serving</li><li>persistence</li><li>remote execution</li><li>transport entrypoints</li><li>hosting one or more namespace surfaces</li></ul><p>A monad can run only for you on localhost, or it can be exposed publicly on the WAN.</p><h3 id="cleaker" tabindex="-1"><code>cleaker</code> <a class="header-anchor" href="#cleaker" aria-label="Permalink to &quot;`cleaker`&quot;">​</a></h3><p><code>cleaker</code> is the ledger interface between <code>.me</code> and the network.</p><p>It owns:</p><ul><li>namespace binding</li><li>parsing and resolution</li><li>attaching <code>.me</code> statements to a ledger</li><li>hydrating a <code>.me</code> back from ledger memories</li><li>public semantic order</li></ul><p><code>cleaker</code> is also the first organized semantic dictionary for <code>.me</code>.</p><p>It gives public structure to things like:</p><ul><li>users</li><li>profiles</li><li>wallets</li><li>devices</li><li>claims</li></ul><h3 id="cleaker-me" tabindex="-1"><code>cleaker.me</code> <a class="header-anchor" href="#cleaker-me" aria-label="Permalink to &quot;`cleaker.me`&quot;">​</a></h3><p><code>cleaker.me</code> is not a different protocol.</p><p>It is a public domain running a monad that adopts the <code>cleaker</code> role as a canonical public root.</p><p>That means:</p><ul><li>infrastructure-wise, it is a public <code>monad.ai</code></li><li>semantically, it acts as a clearing root for public namespaces</li></ul><h2 id="deployment-roles" tabindex="-1">Deployment Roles <a class="header-anchor" href="#deployment-roles" aria-label="Permalink to &quot;Deployment Roles&quot;">​</a></h2><h3 id="local-only-monad" tabindex="-1">Local-only monad <a class="header-anchor" href="#local-only-monad" aria-label="Permalink to &quot;Local-only monad&quot;">​</a></h3><p>A local-only monad:</p><ul><li>runs <code>monad.ai</code> only for you</li><li>uses <code>.me</code>, keys, spaces, and snapshots locally</li><li>does not need to publish a public namespace</li></ul><p>Example:</p><ul><li><code>me://self:read/profile</code></li></ul><h3 id="application-domain" tabindex="-1">Application domain <a class="header-anchor" href="#application-domain" aria-label="Permalink to &quot;Application domain&quot;">​</a></h3><p>An application domain, such as <code>netget.site</code> or <code>orgboat</code>, can:</p><ul><li>ask for your <code>.me</code></li><li>ask for keys or capabilities</li><li>read or write permitted spaces</li><li>run business logic on top of your sovereign identity</li></ul><p>It does <strong>not</strong> need to become a public namespace root.</p><h3 id="public-root" tabindex="-1">Public root <a class="header-anchor" href="#public-root" aria-label="Permalink to &quot;Public root&quot;">​</a></h3><p>A public root is a domain that chooses to expose namespace and ledger behavior publicly.</p><p>Examples:</p><ul><li><code>cleaker.me</code></li><li><code>otherdomainname.com</code></li></ul><p>Any domain running a public <code>monad.ai</code> could adopt this role.</p><h2 id="canonical-address-vs-web-projection" tabindex="-1">Canonical Address vs Web Projection <a class="header-anchor" href="#canonical-address-vs-web-projection" aria-label="Permalink to &quot;Canonical Address vs Web Projection&quot;">​</a></h2><p><code>me://</code> is the canonical semantic address.</p><p><code>https://</code> is one possible public projection of that semantic address.</p><p>Examples:</p><ul><li><p><code>me://ana.cleaker:read/profile</code></p></li><li><p><code>https://ana.cleaker.me/profile</code></p></li><li><p><code>me://ana.otherdomainname.com:read/profile</code></p></li><li><p><code>https://ana.otherdomainname.com/profile</code></p></li></ul><p>The semantic target is primary. The web URL is a projection chosen by the host.</p><h2 id="key-spaces-and-privacy" tabindex="-1">Key Spaces and Privacy <a class="header-anchor" href="#key-spaces-and-privacy" aria-label="Permalink to &quot;Key Spaces and Privacy&quot;">​</a></h2><p>A key can live under your sovereign space:</p><ul><li><code>me://self:read/keys/orgboat.keysCustomName</code></li></ul><p>That usually resolves against your active <code>.me</code>, often on localhost or on your own devices.</p><p>But topology does not imply publicity.</p><p>If a space is replicated to:</p><ul><li>laptop</li><li>iphone</li><li><code>cleaker.me</code></li></ul><p>that does <strong>not</strong> make it public.</p><p>The distinction is:</p><ul><li>topology decides where ciphertext exists</li><li>audience decides who can open it</li></ul><p>So a key space may be hosted on <code>cleaker.me</code> and still remain private if its audience is cryptographically closed.</p><h2 id="one-line-model" tabindex="-1">One-line Model <a class="header-anchor" href="#one-line-model" aria-label="Permalink to &quot;One-line Model&quot;">​</a></h2><ul><li><code>.me</code> thinks in spaces</li><li><code>cleaker</code> ledgerizes and hydrates spaces</li><li><code>monad.ai</code> hosts and serves spaces</li></ul><h2 id="rule" tabindex="-1">Rule <a class="header-anchor" href="#rule" aria-label="Permalink to &quot;Rule&quot;">​</a></h2><ul><li>Every app can use <code>.me</code></li><li>Not every app needs <code>cleaker</code></li><li>Every public root can run <code>monad.ai</code></li><li><code>cleaker.me</code> is only the canonical public root, not the only possible one</li></ul>',64)])])}const u=a(c,[["render",n]]);export{h as __pageData,u as default};
